arguments.script:
const limit = (arguments[0] || 5);
const out = [];
const seen = new Set();
const nodes = document.querySelectorAll('#search .g');
for (const node of nodes) {
  const h3 = node.querySelector('h3');
  const link = h3 ? h3.closest('a') : node.querySelector('a');
  const url = link ? link.href : null;
  const title = h3 ? h3.textContent : null;
  if (!url || !title) { continue; }
  if (seen.has(url)) { continue; }
  seen.add(url);
  const snippetNode = node.querySelector('.VwiC3b, .aCOpRe, .IsZvec');
  const snippet = snippetNode ? snippetNode.textContent : '';
  out.push({position: out.length + 1, title: title.trim(), url, snippet: snippet.trim()});
  if (out.length >= limit) { break; }
}
return out;
